import { useEffect, useRef } from 'react';
import styled from 'styled-components';

const ViewerContainer = styled.div`
  width: 100%;
  height: 200px;
  background-color: #0d1117;
  border-radius: 8px;
  margin-bottom: 12px;
  overflow: hidden;
`;

const Canvas = styled.canvas`
  width: 100%;
  height: 100%;
`;

const GeometryInfo = styled.div`
  padding: 8px 12px;
  background-color: #1e1e1e;
  border-radius: 6px;
  margin-bottom: 8px;
`;

const InfoTitle = styled.div`
  font-size: 14px;
  font-weight: 600;
  color: #4ec9b0;
  margin-bottom: 4px;
`;

const InfoContent = styled.div`
  font-size: 12px;
  color: #888888;
`;

function GeometryViewer({ shapeInfo }) {
  const canvasRef = useRef(null);
  const animationRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    const rect = canvas.getBoundingClientRect();
    canvas.width = rect.width * window.devicePixelRatio;
    canvas.height = rect.height * window.devicePixelRatio;
    ctx.scale(window.devicePixelRatio, window.devicePixelRatio);

    let rotation = 0;

    const drawShape = () => {
      ctx.clearRect(0, 0, rect.width, rect.height);

      ctx.save();
      ctx.translate(rect.width / 2, rect.height / 2);
      ctx.rotate(rotation);

      const size = Math.min(rect.width, rect.height) * 0.3;

      ctx.strokeStyle = '#4ec9b0';
      ctx.lineWidth = 2;
      ctx.fillStyle = 'rgba(78, 201, 176, 0.1)';

      if (shapeInfo.type === 'cube' || !shapeInfo.type) {
        drawCube(ctx, size);
      } else if (shapeInfo.type === 'sphere') {
        drawSphere(ctx, size);
      } else if (shapeInfo.type === 'pyramid') {
        drawPyramid(ctx, size);
      } else if (shapeInfo.type === 'cylinder') {
        drawCylinder(ctx, size);
      } else if (shapeInfo.type === 'cone') {
        drawCone(ctx, size);
      } else {
        drawCube(ctx, size);
      }

      ctx.restore();
      rotation += 0.01;
      animationRef.current = requestAnimationFrame(drawShape);
    };

    drawShape();

    return () => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, [shapeInfo]);

  const drawCube = (ctx, size) => {
    const d = size / 2;

    ctx.beginPath();
    ctx.moveTo(-d, -d);
    ctx.lineTo(d, -d);
    ctx.lineTo(d, d);
    ctx.lineTo(-d, d);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.moveTo(-d, -d);
    ctx.lineTo(-d * 0.7, -d * 1.2);
    ctx.lineTo(d * 0.7, -d * 1.2);
    ctx.lineTo(d, -d);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.moveTo(d, -d);
    ctx.lineTo(d * 0.7, -d * 1.2);
    ctx.lineTo(d * 0.7, d * 0.8);
    ctx.lineTo(d, d);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();
  };

  const drawSphere = (ctx, size) => {
    ctx.beginPath();
    ctx.arc(0, 0, size, 0, Math.PI * 2);
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.ellipse(0, 0, size, size * 0.5, 0, 0, Math.PI * 2);
    ctx.stroke();

    ctx.beginPath();
    ctx.ellipse(0, 0, size, size * 0.5, Math.PI / 2, 0, Math.PI * 2);
    ctx.stroke();
  };

  const drawPyramid = (ctx, size) => {
    ctx.beginPath();
    ctx.moveTo(0, -size);
    ctx.lineTo(size * 0.8, size * 0.6);
    ctx.lineTo(-size * 0.8, size * 0.6);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.moveTo(size * 0.8, size * 0.6);
    ctx.lineTo(0, size * 0.2);
    ctx.lineTo(-size * 0.8, size * 0.6);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();
  };

  const drawCylinder = (ctx, size) => {
    ctx.beginPath();
    ctx.ellipse(0, -size * 0.5, size * 0.6, size * 0.3, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.ellipse(0, size * 0.5, size * 0.6, size * 0.3, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.moveTo(-size * 0.6, -size * 0.5);
    ctx.lineTo(-size * 0.6, size * 0.5);
    ctx.stroke();

    ctx.beginPath();
    ctx.moveTo(size * 0.6, -size * 0.5);
    ctx.lineTo(size * 0.6, size * 0.5);
    ctx.stroke();
  };

  const drawCone = (ctx, size) => {
    ctx.beginPath();
    ctx.moveTo(0, -size);
    ctx.lineTo(size * 0.8, size * 0.6);
    ctx.lineTo(-size * 0.8, size * 0.6);
    ctx.closePath();
    ctx.fill();
    ctx.stroke();

    ctx.beginPath();
    ctx.ellipse(0, size * 0.6, size * 0.8, size * 0.3, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.stroke();
  };

  return (
    <>
      <GeometryInfo>
        <InfoTitle>三维几何图形</InfoTitle>
        <InfoContent>
          形状类型: {shapeInfo.type || '立方体'}
          {shapeInfo.dimensions && (
            <span style={{ marginLeft: '12px' }}>
              尺寸: {shapeInfo.dimensions}
            </span>
          )}
          {shapeInfo.properties && (
            <span style={{ marginLeft: '12px' }}>
              属性: {shapeInfo.properties}
            </span>
          )}
        </InfoContent>
      </GeometryInfo>
      <ViewerContainer>
        <Canvas ref={canvasRef} />
      </ViewerContainer>
    </>
  );
}

export default GeometryViewer;
